INSERT INTO `check_export_templates` VALUES (2002015608740265986,2001298830687023106,'早操迟到通报','','{\"categoryIds\": [], \"checkRounds\": [1], \"includeAllItems\": true, \"deductionItemIds\": [\"2000909845510758402\"]}','{\"columns\": [{\"field\": \"index\", \"label\": \"序号\", \"width\": 60}, {\"field\": \"studentNo\", \"label\": \"学号\", \"width\": 100}, {\"field\": \"studentName\", \"label\": \"姓名\", \"width\": 80}, {\"field\": \"className\", \"label\": \"班级\", \"width\": 120}, {\"field\": \"deductionItemName\", \"label\": \"扣分项\", \"width\": 120}], \"showClassHeader\": true, \"showGradeHeader\": true, \"showDepartmentHeader\": true}','department,grade,class','studentNo','PDF','<h2 style=\"text-align: center;\">学生违纪通报</h2><p style=\"text-align: center;\">{{checkDate}}</p><p style=\"text-indent: 2em;\">根据{{checkDate}}检查结果，以下 <strong>{{totalCount}}</strong> 名学生存在违纪行为，现予以通报批评：</p><p>{{TABLE}}</p><p style=\"text-indent: 2em;\">请以上学生引以为戒，严格遵守学校规章制度。</p><p style=\"text-align: right;\">学生处</p><p style=\"text-align: right;\">{{exportDate}}</p>',0,1,1,'2025-12-19 21:58:11','2025-12-20 15:03:07',1,NULL),(2002276987711795201,2001298830687023106,'2','','{\"categoryIds\": [], \"checkRounds\": [], \"includeAllItems\": true, \"deductionItemIds\": []}','{\"columns\": [{\"field\": \"studentName\", \"label\": \"姓名\", \"width\": 80}, {\"field\": \"className\", \"label\": \"班级\", \"width\": 120}, {\"field\": \"deductionItemName\", \"label\": \"扣分项\", \"width\": 120}], \"showClassHeader\": true, \"showGradeHeader\": true, \"showDepartmentHeader\": true}','department,grade,class','studentNo','PDF','<h2 style=\"text-align: center;\">学生违纪通报</h2>\n<p style=\"text-align: center;\">{{checkDate}}</p>\n<p style=\"text-indent: 2em; line-height: 1.8;\">根据{{checkDate}}检查结果，以下 <strong>{{totalCount}}</strong> 名学生存在违纪行为，现予以通报批评：</p>\n<p>{{TABLE}}</p>\n<p style=\"text-indent: 2em; line-height: 1.8;\">请以上学生引以为戒，严格遵守学校规章制度。</p>\n<p style=\"text-align: right;\">学生处</p>\n<p style=\"text-align: right;\">{{exportDate}}</p>',0,1,1,'2025-12-20 15:16:49','2025-12-20 15:16:49',0,NULL),(2002306268018040834,2001298830687023106,'32','','{\"categoryIds\": [], \"checkRounds\": [], \"includeAllItems\": true, \"deductionItemIds\": []}','{\"columns\": [{\"field\": \"departmentName\", \"label\": \"院系\", \"width\": 120}, {\"field\": \"gradeName\", \"label\": \"年级\", \"width\": 100}, {\"field\": \"className\", \"label\": \"班级\", \"width\": 120}, {\"field\": \"studentName\", \"label\": \"姓名\", \"width\": 80}], \"showClassHeader\": true, \"showGradeHeader\": false, \"showDepartmentHeader\": false}','department,grade,class','studentNo','PDF','<h2 style=\"text-align: center;\"><strong>经济与信息技术系早读迟到检查</strong></h2>\n<p style=\"text-align: center;\">{{checkDate}}</p>\n<p style=\"text-indent: 2em; line-height: 1.8;\">根据{{checkDate}}检查结果，以下 <strong>{{totalCount}}</strong> 名学生存在违纪行为，现予以通报批评：</p>\n<p>{{TABLE}}</p>\n<p style=\"text-indent: 2em; line-height: 1.8;\">请以上学生引以为戒，严格遵守学校规章制度。</p>\n<p style=\"text-align: right;\">经济与信息技术系</p>\n<p style=\"text-align: right;\">{{exportDate}}</p>',0,1,1,'2025-12-20 17:13:10','2025-12-20 17:13:10',0,NULL),(2002322822227091457,2001298830687023106,'发的是的撒','','{\"categoryIds\": [], \"checkRounds\": [], \"includeAllItems\": true, \"deductionItemIds\": []}','{\"columns\": [{\"field\": \"departmentName\", \"label\": \"院系\", \"width\": 120}, {\"field\": \"gradeName\", \"label\": \"年级\", \"width\": 100}, {\"field\": \"className\", \"label\": \"班级\", \"width\": 120}, {\"field\": \"studentName\", \"label\": \"姓名\", \"width\": 80}], \"showClassHeader\": true, \"showGradeHeader\": false, \"showDepartmentHeader\": false}','department,grade,class','studentNo','PDF','<div style=\"max-width: 680px; margin: 0 auto; padding: 40px 60px; font-family: SimSun, serif;\"><!-- 发文机关标识（红头） -->\n<div style=\"text-align: center; margin-bottom: 20px;\">\n<h1 style=\"color: #c00000; font-size: 32px; font-weight: bold; font-family: \'SimHei\', sans-serif; letter-spacing: 8px; margin: 0;\">XX学校学生处</h1>\n</div>\n<!-- 发文字号 --><!-- 红色分隔线 --><hr style=\"border: none; border-top: 2px solid #C00000; margin: 20px 0;\"><!-- 标题 -->\n<h2 style=\"text-align: center; font-size: 22px; font-weight: bold; font-family: \'SimHei\', sans-serif; margin: 30px 0; line-height: 1.5;\">关于{{checkDate}}学生违纪情况的通报</h2>\n<!-- 主送单位 -->\n<p style=\"font-size: 16px; line-height: 2; margin-bottom: 15px;\">各院系、各班级：</p>\n<!-- 正文 -->\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">为进一步加强学生日常行为规范管理，维护正常的教学秩序，根据{{checkDate}}检查结果，共有 <strong>{{totalCount}}</strong> 名学生存在违纪行为，现将有关情况通报如下：</p>\n<!-- 数据表格 -->\n<div style=\"margin: 25px 0;\">{{TABLE}}</div>\n<!-- 处理意见 -->\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">以上违纪学生的行为已违反了《学生手册》相关规定，根据学校有关规章制度，现予以通报批评，并扣除相应量化考核分数。</p>\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">希望以上同学认真反思，引以为戒，严格遵守学校各项规章制度。各院系、各班级要以此为鉴，进一步加强学生教育管理工作，杜绝类似事件再次发生。</p>\n<!-- 落款 -->\n<div style=\"margin-top: 50px; text-align: right; padding-right: 80px;\">\n<p style=\"font-size: 16px; line-height: 2; margin: 0;\">学生处</p>\n<p style=\"font-size: 16px; line-height: 2; margin: 0;\">&nbsp; &nbsp; {{exportDate}}</p>\n</div>\n<!-- 页脚信息 --></div>',0,1,1,'2025-12-20 18:18:57','2025-12-20 18:18:57',0,NULL),(2002362622019665922,2001298830687023106,'测试1','','{\"categoryIds\": [], \"checkRounds\": [], \"includeAllItems\": true, \"deductionItemIds\": []}','{\"columns\": [{\"field\": \"departmentName\", \"label\": \"院系\", \"width\": 120, \"mergeType\": \"group\", \"groupOrder\": 1}, {\"field\": \"gradeName\", \"label\": \"年级\", \"width\": 100, \"mergeType\": \"group\", \"groupOrder\": 2}, {\"field\": \"className\", \"label\": \"班级\", \"width\": 120, \"mergeType\": \"group\", \"groupOrder\": 3}, {\"field\": \"studentName\", \"label\": \"姓名\", \"width\": 80, \"mergeType\": \"concat\", \"separator\": \"、\", \"groupByField\": \"className\"}, {\"field\": \"headTeacher\", \"label\": \"班主任\", \"width\": 80, \"mergeType\": \"group\", \"groupOrder\": 4}, {\"align\": \"left\", \"field\": \"deductionItemName\", \"label\": \"扣分项\", \"width\": 120, \"mergeType\": \"\"}], \"fontSize\": \"14px\", \"rowHeight\": \"auto\", \"textAlign\": \"center\", \"hoverColor\": \"#e6f7ff\", \"lineHeight\": \"1.5\", \"zebraColor\": \"#f9f9f9\", \"borderColor\": \"#000000\", \"borderStyle\": \"solid\", \"borderWidth\": \"1px\", \"cellPadding\": \"8px\", \"mergeConfig\": {\"enabled\": false, \"separator\": \"、\", \"concatDataRows\": false, \"hierarchyLevels\": []}, \"zebraStripes\": false, \"headerBgColor\": \"#ffffff\", \"verticalAlign\": \"middle\", \"headerFontSize\": \"14px\", \"hoverHighlight\": false, \"headerTextColor\": \"#000000\", \"showClassHeader\": true, \"showGradeHeader\": false, \"headerFontWeight\": \"bold\", \"showDepartmentHeader\": false}','department,grade,class','studentNo','PDF','<div style=\"max-width: 680px; margin: 0 auto; padding: 40px 60px; font-family: SimSun, serif;\">\n<div style=\"text-align: center; margin-bottom: 20px;\">\n<h1 style=\"color: #c00000; font-size: 32px; font-weight: bold; font-family: SimHei, sans-serif; letter-spacing: 8px; margin: 0px;\">经济与信息技术系学生管理办公室</h1>\n</div>\n<hr style=\"border: none; border-top: 2px solid #C00000; margin: 20px 0;\">\n<h2 style=\"text-align: center; font-size: 22px; font-weight: bold; font-family: \'SimHei\', sans-serif; margin: 30px 0; line-height: 1.5;\">关于{{checkDate}}学生违纪情况的通报</h2>\n<p style=\"font-size: 16px; line-height: 2; margin-bottom: 15px;\">各院系、各班级：</p>\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">为进一步加强学生日常行为规范管理，维护正常的教学秩序，根据{{checkDate}}检查结果，共有 <strong>{{totalCount}}</strong> 名学生存在违纪行为，现将有关情况通报如下：</p>\n<div style=\"margin: 25px 0;\">{{TABLE}}</div>\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">以上违纪学生的行为已违反了《学生手册》相关规定，根据学校有关规章制度，现予以通报批评，并扣除相应量化考核分数。</p>\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">希望以上同学认真反思，引以为戒，严格遵守学校各项规章制度。各院系、各班级要以此为鉴，进一步加强学生教育管理工作，杜绝类似事件再次发生a 。</p>\n<div style=\"margin-top: 50px; text-align: right; padding-right: 80px;\">\n<p style=\"font-size: 16px; line-height: 2; margin: 0;\">经济与信息技术系学生管理办公室</p>\n<p style=\"font-size: 16px; line-height: 2; margin: 0;\">{{exportDate}}&nbsp; &nbsp;&nbsp;</p>\n</div>\n</div>',0,1,1,'2025-12-20 20:57:06','2025-12-20 20:57:06',0,NULL);
