--
-- Table structure for table `check_item_appeals`
--

DROP TABLE IF EXISTS `check_item_appeals`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `check_item_appeals` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `item_id` bigint NOT NULL COMMENT 'FK → check_record_items.id',
  `record_id` bigint NOT NULL,
  `class_id` bigint DEFAULT NULL,
  `class_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `category_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `item_name` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `original_deduct_score` decimal(10,2) DEFAULT NULL,
  `appeal_reason` text COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申诉理由',
  `expected_score` decimal(10,2) DEFAULT NULL COMMENT '期望分数',
  `appeal_photos` text COLLATE utf8mb4_unicode_ci COMMENT '申诉证据照片',
  `appeal_videos` text COLLATE utf8mb4_unicode_ci,
  `appealer_id` bigint DEFAULT NULL,
  `appealer_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `appeal_time` datetime NOT NULL,
  `appeal_status` tinyint DEFAULT '1' COMMENT '状态: 1=待处理, 2=已通过, 3=已驳回, 4=已撤销',
  `handler_id` bigint DEFAULT NULL,
  `handler_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `handle_time` datetime DEFAULT NULL,
  `handle_result` text COLLATE utf8mb4_unicode_ci COMMENT '处理结果说明',
  `withdrawn_at` datetime DEFAULT NULL,
  `withdraw_reason` text COLLATE utf8mb4_unicode_ci,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted` int DEFAULT '0' COMMENT '逻辑删除标志',
  `appeal_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '申诉编号',
  `record_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '检查记录编号',
  `class_stat_id` bigint DEFAULT NULL COMMENT '班级统计ID',
  `grade_id` bigint DEFAULT NULL COMMENT '年级ID',
  `category_id` bigint DEFAULT NULL COMMENT '类别ID',
  `original_score` decimal(10,2) DEFAULT NULL COMMENT '原始扣分',
  `link_info` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联信息',
  `original_photo_urls` text COLLATE utf8mb4_unicode_ci COMMENT '原始照片URLs',
  `original_remark` text COLLATE utf8mb4_unicode_ci COMMENT '原始备注',
  `appeal_type` int DEFAULT '1' COMMENT '申诉类型',
  `evidence_urls` text COLLATE utf8mb4_unicode_ci COMMENT '申诉证据URLs',
  `appellant_id` bigint DEFAULT NULL COMMENT '申诉人ID',
  `appellant_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '申诉人姓名',
  `appellant_role` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '申诉人角色',
  `appeal_deadline` datetime DEFAULT NULL COMMENT '申诉截止时间',
  `status` int DEFAULT '1' COMMENT '申诉状态',
  `current_step` int DEFAULT '1' COMMENT '当前审批步骤',
  `final_reviewer_id` bigint DEFAULT NULL COMMENT '最终审核人ID',
  `final_reviewer_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '最终审核人姓名',
  `final_review_time` datetime DEFAULT NULL COMMENT '最终审核时间',
  `final_review_opinion` text COLLATE utf8mb4_unicode_ci COMMENT '最终审核意见',
  `adjusted_score` decimal(10,2) DEFAULT NULL COMMENT '调整后分数',
  `score_change` decimal(10,2) DEFAULT NULL COMMENT '分数变化',
  `publicity_start_time` datetime DEFAULT NULL COMMENT '公示开始时间',
  `publicity_end_time` datetime DEFAULT NULL COMMENT '公示结束时间',
  `publicity_days` int DEFAULT NULL COMMENT '公示天数',
  `effective_time` datetime DEFAULT NULL COMMENT '生效时间',
  `approval_flow_snapshot` text COLLATE utf8mb4_unicode_ci COMMENT '审批流程快照',
  PRIMARY KEY (`id`),
  KEY `idx_item` (`item_id`),
  KEY `idx_record` (`record_id`),
  KEY `idx_class` (`class_id`),
  KEY `idx_status` (`appeal_status`),
  KEY `idx_appeal_time` (`appeal_time`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='申诉表';
/*!40101 SET character_set_client = @saved_cs_client */;

