  KEY `idx_code` (`item_code`),
  CONSTRAINT `fk_items_category` FOREIGN KEY (`category_id`) REFERENCES `check_categories` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1996943333733277698 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='检查项字典表';
