--
-- Table structure for table `check_record_class_stats`
--

DROP TABLE IF EXISTS `check_record_class_stats`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `check_record_class_stats` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `record_id` bigint NOT NULL COMMENT 'FK → check_records.id',
  `class_id` bigint NOT NULL COMMENT 'FK → classes.id',
  `class_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '班级名称快照',
  `grade_id` bigint DEFAULT NULL COMMENT '年级ID',
  `grade_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '年级名称',
  `class_size` int DEFAULT NULL COMMENT '班级人数快照',
  `teacher_id` bigint DEFAULT NULL,
  `teacher_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '班主任快照',
  `total_items` int NOT NULL DEFAULT '0' COMMENT '扣分项总数',
  `total_score` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '总扣分',
  `hygiene_score` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '卫生扣分',
  `discipline_score` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '纪律扣分',
  `attendance_score` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '出勤扣分',
  `other_score` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '其他扣分',
  `score_level` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '评分等级',
  `original_deduct` decimal(10,2) DEFAULT '0.00' COMMENT '原始总扣分',
  `weight_config_id` bigint DEFAULT NULL COMMENT '使用的加权方案',
  `weight_factor` decimal(5,2) DEFAULT '1.00' COMMENT '权重系数',
  `weighted_deduct` decimal(10,2) DEFAULT '0.00' COMMENT '加权后扣分',
  `final_score` decimal(10,2) DEFAULT '0.00' COMMENT '最终得分 = 100 + weighted_deduct',
  `ranking` int DEFAULT NULL COMMENT '全校排名',
  `grade_ranking` int DEFAULT NULL COMMENT '年级排名',
  `appeal_count` int DEFAULT '0',
  `appeal_passed` int DEFAULT '0',
  `appeal_pending` int DEFAULT '0',
  `vs_avg_score` decimal(10,2) DEFAULT NULL COMMENT '与平均分差值',
  `vs_last_score` decimal(10,2) DEFAULT NULL COMMENT '与上次差值',
  `stat_version` int DEFAULT '1',
  `is_latest` tinyint DEFAULT '1',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `department_id` bigint DEFAULT NULL,
  `department_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `grade_level` int DEFAULT NULL,
  `deduction_count` int DEFAULT '0',
  `dormitory_score` decimal(10,2) DEFAULT '0.00',
  `weight_enabled` tinyint DEFAULT '0',
  `standard_size` int DEFAULT NULL,
  `weighted_total_score` decimal(10,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_record_class_latest` (`record_id`,`class_id`,`is_latest`),
  KEY `idx_record` (`record_id`),
  KEY `idx_class` (`class_id`),
  KEY `idx_ranking` (`record_id`,`ranking`),
  CONSTRAINT `fk_stats_class` FOREIGN KEY (`class_id`) REFERENCES `classes` (`id`),
  CONSTRAINT `fk_stats_record` FOREIGN KEY (`record_id`) REFERENCES `check_records_old` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=10231 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='班级统计表(精简版)';
/*!40101 SET character_set_client = @saved_cs_client */;

