--
-- Table structure for table `check_record_items`
--

DROP TABLE IF EXISTS `check_record_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `check_record_items` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `record_id` bigint NOT NULL COMMENT '检查记录ID',
  `class_stat_id` bigint DEFAULT NULL COMMENT '班级统计ID',
  `class_id` bigint DEFAULT NULL COMMENT '班级ID',
  `category_id` bigint DEFAULT NULL COMMENT '检查类别ID',
  `category_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '类别名称',
  `item_id` bigint DEFAULT NULL COMMENT '扣分项ID',
  `item_name` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '扣分项名称',
  `deduct_mode` int DEFAULT '1' COMMENT '扣分模式(1固定2按人数3区间)',
  `deduct_score` decimal(10,2) DEFAULT '0.00' COMMENT '扣分',
  `person_count` int DEFAULT '0' COMMENT '涉及人数',
  `link_type` int DEFAULT '0' COMMENT '关联类型(0无1宿舍2教室)',
  `link_id` bigint DEFAULT NULL COMMENT '关联对象ID',
  `link_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联对象编号',
  `link_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联对象编号别名',
  `link_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联对象名称',
  `check_round` int DEFAULT '1' COMMENT '检查轮次',
  `student_names` text COLLATE utf8mb4_unicode_ci COMMENT '关联学生姓名',
  `photo_urls` text COLLATE utf8mb4_unicode_ci COMMENT '照片URLs',
  `remark` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注说明',
  `appeal_status` int DEFAULT '0' COMMENT '申诉状态(0未申诉1申诉中2已通过3已驳回)',
  `appeal_id` bigint DEFAULT NULL COMMENT '申诉记录ID',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`id`),
  KEY `idx_record_id` (`record_id`),
  KEY `idx_class_stat_id` (`class_stat_id`),
  KEY `idx_class_id` (`class_id`)
) ENGINE=InnoDB AUTO_INCREMENT=37 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='检查记录-扣分明细V3';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `check_record_items`
--

