DROP TABLE IF EXISTS `check_record_items_old`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `check_record_items_old` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `record_id` bigint NOT NULL COMMENT 'FK → check_records.id',
  `class_stat_id` bigint NOT NULL COMMENT 'FK → check_record_class_stats.id',
  `category_id` bigint NOT NULL COMMENT 'FK → check_categories.id',
  `category_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '类别名称快照',
  `item_id` bigint DEFAULT NULL COMMENT 'FK → check_items.id (可为NULL,临时项)',
  `item_name` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '检查项名称',
  `deduct_mode` tinyint DEFAULT '1' COMMENT '扣分模式: 1=按次, 2=按人',
  `deduct_score` decimal(10,2) NOT NULL COMMENT '扣分: -5.00',
  `person_count` int DEFAULT NULL COMMENT '涉及人数(按人扣分时)',
  `link_type` tinyint DEFAULT '0' COMMENT '关联类型: 0=无, 1=宿舍, 2=学生, 3=教室',
  `link_id` bigint DEFAULT NULL COMMENT '关联ID',
  `link_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联编号: 201宿舍',
  `photo_urls` text COLLATE utf8mb4_unicode_ci COMMENT '照片URLs (JSON数组)',
  `video_urls` text COLLATE utf8mb4_unicode_ci COMMENT '视频URLs',
  `location_detail` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '具体位置',
  `issue_description` text COLLATE utf8mb4_unicode_ci COMMENT '问题详细描述',
  `remark` text COLLATE utf8mb4_unicode_ci COMMENT '备注',
  `appeal_status` tinyint DEFAULT '0' COMMENT '申诉状态: 0=未申诉, 1=待处理, 2=已通过, 3=已驳回',
  `appeal_id` bigint DEFAULT NULL COMMENT 'FK → check_item_appeals.id',
  `is_temporary` tinyint DEFAULT '0' COMMENT '是否临时项: 0=模板项, 1=临时项',
  `temp_approved` tinyint DEFAULT NULL COMMENT '临时项审批状态',
  `temp_approver_id` bigint DEFAULT NULL,
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `created_by` bigint DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_record` (`record_id`),
  KEY `idx_class_stat` (`class_stat_id`),
  KEY `idx_category` (`category_id`),
  KEY `idx_item` (`item_id`),
  KEY `idx_appeal` (`appeal_status`),
  CONSTRAINT `fk_record_items_category` FOREIGN KEY (`category_id`) REFERENCES `check_categories` (`id`),
  CONSTRAINT `fk_record_items_class_stat` FOREIGN KEY (`class_stat_id`) REFERENCES `check_record_class_stats` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_record_items_record` FOREIGN KEY (`record_id`) REFERENCES `check_records_old` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='扣分明细表';
