  KEY `idx_status` (`status`),
  KEY `idx_deleted` (`deleted`),
  KEY `idx_check_type` (`check_type`),
  KEY `idx_plan_id` (`plan_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='检查记录V3表';
