  CONSTRAINT `fk_records_template` FOREIGN KEY (`template_id`) REFERENCES `check_templates` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=1005 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='检查记录表(合并daily_checks和check_records_v3)';
