/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `check_records_v3_deprecated` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '涓婚敭ID',
  `daily_check_id` bigint NOT NULL COMMENT '鍏宠仈鏃ュ父妫?煡ID',
  `weight_config_id` bigint DEFAULT NULL COMMENT '鍔犳潈閰嶇疆ID',
  `weight_enabled` tinyint DEFAULT '1' COMMENT '鏄?惁鍚?敤鍔犳潈',
  `weight_mode_snapshot` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Weight mode snapshot',
  `standard_size_mode_snapshot` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Standard size mode snapshot',
  `standard_size_snapshot_value` int DEFAULT NULL COMMENT 'Standard size value snapshot',
  `appeal_config_id` bigint DEFAULT NULL COMMENT '鐢宠瘔閰嶇疆ID',
  `record_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '璁板綍缂栧彿 REC-20251101-001',
  `check_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '妫?煡鍚嶇О',
  `check_date` date NOT NULL COMMENT '妫?煡鏃ユ湡',
  `check_time` datetime DEFAULT NULL COMMENT '检查时间',
  `check_type` tinyint DEFAULT '1' COMMENT '妫?煡绫诲瀷(1鏃ュ父2涓撻」)',
  `checker_id` bigint NOT NULL COMMENT '妫?煡浜篒D',
  `checker_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '妫?煡浜哄?鍚',
  `total_classes` int DEFAULT '0' COMMENT '娑夊強鐝?骇鏁',
  `total_categories` int DEFAULT '0' COMMENT '妫?煡绫诲埆鏁',
  `total_items` int DEFAULT '0' COMMENT '鎵ｅ垎椤规?鏁',
  `total_score` decimal(10,2) DEFAULT '0.00' COMMENT '鎬绘墸鍒',
  `avg_score` decimal(10,2) DEFAULT '0.00' COMMENT '骞冲潎鎵ｅ垎',
  `max_score` decimal(10,2) DEFAULT '0.00' COMMENT '鏈?珮鎵ｅ垎',
  `min_score` decimal(10,2) DEFAULT '0.00' COMMENT '鏈?綆鎵ｅ垎',
  `status` tinyint DEFAULT '1' COMMENT '状态(1草稿2已完成3已发布4已归档)',
  `publish_time` datetime DEFAULT NULL COMMENT '鍙戝竷鏃堕棿',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '澶囨敞璇存槑',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  `deleted` tinyint DEFAULT '0' COMMENT '鍒犻櫎鏍囧織',
  `publisher_id` bigint DEFAULT NULL COMMENT '鍙戝竷浜篒D',
  `publisher_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鍙戝竷浜哄?鍚',
  `standard_mode_override` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '标准人数模式覆盖(NULL=使用全局,FIXED=固定,DYNAMIC=动态,SNAPSHOT=使用快照)',
  `custom_standard_sizes` json DEFAULT NULL COMMENT '自定义标准人数(按年级,JSON格式)',
  `standard_snapshot` json DEFAULT NULL COMMENT '标准人数快照(创建时的实际数据)',
  `snapshot_created_at` datetime DEFAULT NULL COMMENT '快照创建时间',
  `snapshot_locked` tinyint DEFAULT '0' COMMENT '快照是否锁定(0=未锁定可重算,1=已锁定不可改)',
  `recalculation_history` json DEFAULT NULL COMMENT '重新计算历史记录',
  `standard_mode_description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '标准人数模式说明(用于显示)',
  PRIMARY KEY (`id`),
  UNIQUE KEY `daily_check_id` (`daily_check_id`),
  UNIQUE KEY `record_code` (`record_code`),
  KEY `idx_daily_check` (`daily_check_id`),
  KEY `idx_date` (`check_date`),
  KEY `idx_checker` (`checker_id`),
  KEY `idx_status` (`status`),
  KEY `idx_record_code` (`record_code`),
  KEY `idx_weight_config` (`weight_config_id`),
  KEY `idx_appeal_config` (`appeal_config_id`),
  KEY `idx_date_status` (`check_date`,`status`) COMMENT '鏃ユ湡鐘舵?缁勫悎绱㈠紩-鐢ㄤ簬鍒楄〃鏌ヨ?',
  KEY `idx_checker_date` (`checker_id`,`check_date` DESC) COMMENT '妫?煡鍛樻棩鏈熺储寮?鐢ㄤ簬涓?汉鍘嗗彶鏌ヨ?',
  KEY `idx_publish_time` (`publish_time`) COMMENT '鍙戝竷鏃堕棿绱㈠紩-鐢ㄤ簬鏃堕棿鑼冨洿绛涢?',
  KEY `idx_list_cover` (`check_date`,`status`,`id`,`check_name`,`total_score`,`avg_score`) COMMENT '鍒楄〃椤佃?鐩栫储寮?鍖呭惈甯哥敤鏄剧ず瀛楁?',
  KEY `idx_check_date_status` (`check_date`,`status`,`deleted`),
  KEY `idx_check_type_date` (`check_type`,`check_date`,`deleted`),
  KEY `idx_check_date` (`check_date`,`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='妫?煡璁板綍V3-涓昏〃';
