DROP TABLE IF EXISTS `class_quantification_summary`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `class_quantification_summary` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '涓婚敭ID',
  `class_id` bigint NOT NULL COMMENT '鐝?骇ID',
  `summary_date` date NOT NULL COMMENT '缁熻?鏃ユ湡',
  `summary_type` tinyint NOT NULL COMMENT '缁熻?绫诲瀷 1鏃?2鍛?3鏈?4瀛︽湡 5瀛﹀勾',
  `total_score` decimal(10,2) DEFAULT '0.00' COMMENT '鎬绘墸鍒',
  `check_count` int DEFAULT '0' COMMENT '妫?煡娆℃暟',
  `appeal_count` int DEFAULT '0' COMMENT '鐢宠瘔娆℃暟',
  `revision_count` int DEFAULT '0' COMMENT '淇??娆℃暟',
  `rank_in_grade` int DEFAULT NULL COMMENT '骞寸骇鎺掑悕',
  `rank_in_dept` int DEFAULT NULL COMMENT '绯婚儴鎺掑悕',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_class_date_type` (`class_id`,`summary_date`,`summary_type`),
  KEY `idx_summary_date` (`summary_date`),
  KEY `idx_summary_type` (`summary_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='鐝?骇閲忓寲姹囨?琛';
/*!40101 SET character_set_client = @saved_cs_client */;

