DROP TABLE IF EXISTS `class_size_snapshots`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `class_size_snapshots` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '涓婚敭ID',
  `class_id` bigint NOT NULL COMMENT '鐝?骇ID',
  `grade_id` bigint DEFAULT NULL COMMENT '年级ID',
  `snapshot_date` date NOT NULL COMMENT '蹇?収鏃ユ湡',
  `student_count` int NOT NULL COMMENT '瀛︾敓鎬绘暟',
  `active_count` int DEFAULT NULL COMMENT '鍦ㄦ牎浜烘暟(鎺掗櫎浼戝?/璇峰亣)',
  `male_count` int DEFAULT NULL COMMENT '鐢风敓浜烘暟',
  `female_count` int DEFAULT NULL COMMENT '濂崇敓浜烘暟',
  `snapshot_source` varchar(20) DEFAULT 'AUTO' COMMENT '蹇?収鏉ユ簮(AUTO=鑷?姩,MANUAL=鎵嬪姩,PUBLISH=鍙戝竷妫?煡鏃?',
  `record_id` bigint DEFAULT NULL COMMENT '关联的检查记录ID',
  `standard_size` int DEFAULT NULL COMMENT '标准人数',
  `usage_count` int DEFAULT '0' COMMENT '使用次数',
  `is_used` tinyint(1) DEFAULT '0' COMMENT '是否已使用',
  `remark` varchar(500) DEFAULT NULL COMMENT '备注',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_class_date` (`class_id`,`snapshot_date`),
  KEY `idx_snapshot_date` (`snapshot_date`),
  KEY `idx_class_id` (`class_id`),
  KEY `idx_record_id` (`record_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='鐝?骇浜烘暟蹇?収琛';
