--
-- Table structure for table `daily_check_details`
--

DROP TABLE IF EXISTS `daily_check_details`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `daily_check_details` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '涓婚敭ID',
  `check_id` bigint NOT NULL COMMENT '鏃ュ父妫?煡ID',
  `check_round` int DEFAULT '1' COMMENT '检查轮次(第几次)',
  `category_id` bigint NOT NULL COMMENT '妫?煡绫诲埆ID',
  `class_id` bigint NOT NULL COMMENT '鐝?骇ID',
  `deduction_item_id` bigint NOT NULL COMMENT '鎵ｅ垎椤笽D',
  `deduction_item_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鎵ｅ垎椤瑰悕绉',
  `deduct_mode` tinyint DEFAULT '1' COMMENT '鎵ｅ垎妯″紡:1=鍥哄畾,2=鎸変汉鏁?3=鍖洪棿',
  `link_type` tinyint DEFAULT '0' COMMENT '鍏宠仈绫诲瀷:0=鏃犲叧鑱?1=瀹胯垗,2=鏁欏?',
  `link_id` bigint DEFAULT NULL COMMENT '鍏宠仈瀵硅薄ID',
  `link_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鍏宠仈瀵硅薄缂栧彿',
  `deduct_score` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '瀹為檯鎵ｅ垎',
  `person_count` int DEFAULT NULL COMMENT '杩濊?浜烘暟',
  `student_ids` varchar(1000) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联学生ID列表(逗号分隔)',
  `student_names` varchar(2000) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '关联学生姓名(逗号分隔)',
  `total_students` int DEFAULT NULL COMMENT '瀹胯垗鎬讳汉鏁',
  `class_students` int DEFAULT NULL COMMENT '璇ョ彮鍦ㄥ?鑸嶇殑浜烘暟',
  `score_ratio` decimal(10,4) DEFAULT NULL COMMENT '鍒嗘暟鍒嗘憡姣斾緥',
  `checker_id` bigint DEFAULT NULL COMMENT '妫?煡浜篒D',
  `check_time` datetime DEFAULT NULL COMMENT '妫?煡鏃堕棿',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '鎵ｅ垎璇存槑',
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '璇佹嵁鍥剧墖JSON鏁扮粍',
  `is_revised` tinyint DEFAULT '0' COMMENT '鏄?惁宸蹭慨璁?0=鍚?1=鏄',
  `original_score` decimal(10,2) DEFAULT NULL COMMENT '鍘熷?鎵ｅ垎',
  `revised_score` decimal(10,2) DEFAULT NULL COMMENT '淇??鍚庢墸鍒',
  `revision_reason` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '淇??鍘熷洜',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '澶囨敞',
  `photo_urls` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '鍥剧墖URLs',
  `appeal_status` tinyint DEFAULT '0' COMMENT '鐢宠瘔鐘舵?:0=鏈?敵璇?1=鐢宠瘔涓?2=鐢宠瘔閫氳繃,3=鐢宠瘔椹冲洖',
  `created_by` bigint DEFAULT NULL COMMENT '鍒涘缓浜篒D',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  `deleted` tinyint DEFAULT '0' COMMENT '閫昏緫鍒犻櫎:0=鏈?垹闄?1=宸插垹闄',
  PRIMARY KEY (`id`),
  KEY `idx_check_id` (`check_id`),
  KEY `idx_category_id` (`category_id`),
  KEY `idx_class_id` (`class_id`),
  KEY `idx_link` (`link_type`,`link_id`),
  KEY `idx_appeal_status` (`appeal_status`),
  KEY `idx_check_class` (`check_id`,`class_id`),
  KEY `idx_check_round` (`check_round`)
) ENGINE=InnoDB AUTO_INCREMENT=2002426779733598211 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='鏃ュ父妫?煡鎵ｅ垎鏄庣粏琛';
/*!40101 SET character_set_client = @saved_cs_client */;

