DROP TABLE IF EXISTS `daily_check_targets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `daily_check_targets` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `check_id` bigint NOT NULL COMMENT '检查ID',
  `target_type` tinyint NOT NULL COMMENT '目标类型: 1班级 2年级 3院系',
  `target_id` bigint NOT NULL COMMENT '目标ID',
  `target_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '目标名称',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint DEFAULT '0' COMMENT '删除标记: 0正常 1已删除',
  PRIMARY KEY (`id`),
  KEY `idx_check_id` (`check_id`),
  CONSTRAINT `daily_check_targets_ibfk_1` FOREIGN KEY (`check_id`) REFERENCES `daily_checks` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2002277087213269004 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='日常检查目标表';
