--
-- Table structure for table `daily_check_weight_configs`
--

DROP TABLE IF EXISTS `daily_check_weight_configs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `daily_check_weight_configs` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `daily_check_id` bigint NOT NULL COMMENT '日常检查ID',
  `weight_config_id` bigint NOT NULL COMMENT '加权配置ID',
  `color_code` varchar(20) DEFAULT '#1890ff' COMMENT '颜色标记（16进制颜色码）',
  `color_name` varchar(50) DEFAULT NULL COMMENT '颜色名称（如：蓝色、绿色）',
  `apply_scope` varchar(20) DEFAULT 'CATEGORY' COMMENT '应用范围：CATEGORY=分类级别, ITEM=扣分项级别',
  `apply_category_ids` text COMMENT '应用的分类ID列表（JSON数组）',
  `apply_item_ids` text COMMENT '应用的扣分项ID列表（JSON数组）',
  `is_default` tinyint DEFAULT '0' COMMENT '是否为默认配置（未指定时使用）',
  `priority` int DEFAULT '0' COMMENT '优先级（数字越大优先级越高）',
  `weight_config_snapshot` text COMMENT '加权配置快照（JSON格式）',
  `calculated_standard_size` int DEFAULT NULL COMMENT '计算后的标准人数',
  `sort_order` int DEFAULT '0' COMMENT '排序顺序',
  `remarks` varchar(500) DEFAULT NULL COMMENT '备注说明',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted` tinyint DEFAULT '0',
  PRIMARY KEY (`id`),
  KEY `idx_daily_check_id` (`daily_check_id`),
  KEY `idx_weight_config_id` (`weight_config_id`),
  KEY `idx_is_default` (`is_default`),
  CONSTRAINT `fk_dwc_daily_check` FOREIGN KEY (`daily_check_id`) REFERENCES `daily_checks` (`id`),
  CONSTRAINT `fk_dwc_weight_config` FOREIGN KEY (`weight_config_id`) REFERENCES `class_weight_configs` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2002277086164692994 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='日常检查加权配置关联表（支持多加权配置）';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `daily_check_weight_configs`
--

LOCK TABLES `daily_check_weight_configs` WRITE;
/*!40000 ALTER TABLE `daily_check_weight_configs` DISABLE KEYS */;
