--
-- Table structure for table `daily_checks`
--

DROP TABLE IF EXISTS `daily_checks`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `daily_checks` (
  `id` bigint NOT NULL COMMENT '主键ID',
  `plan_id` bigint DEFAULT NULL COMMENT '所属检查计划ID',
  `check_date` date NOT NULL COMMENT '检查日期',
  `check_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '检查名称',
  `template_id` bigint DEFAULT NULL COMMENT '使用的模板ID',
  `check_type` tinyint DEFAULT '1' COMMENT '检查类型 1日常检查 2专项检查',
  `total_rounds` int DEFAULT '1' COMMENT '总轮次数',
  `round_names` json DEFAULT NULL COMMENT '轮次名称数组',
  `status` tinyint DEFAULT '0' COMMENT '状态 0未开始 1进行中 2已提交 3已发布',
  `record_generated` tinyint NOT NULL DEFAULT '0' COMMENT '鏄?惁宸茬敓鎴愯?褰曪細0=鍚?1=鏄',
  `record_id` bigint DEFAULT NULL COMMENT '鐢熸垚鐨勬?鏌ヨ?褰旾D',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '检查说明',
  `excluded_targets` json DEFAULT NULL COMMENT '排除的目标列表(JSON格式)',
  `checker_id` bigint DEFAULT NULL COMMENT '检查人ID',
  `checker_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '检查人姓名',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `weight_config_id` bigint DEFAULT NULL COMMENT '加权方案ID',
  `enable_weight` tinyint DEFAULT '0' COMMENT '是否启用加权 0否 1是',
  `custom_standard_size` int DEFAULT NULL COMMENT '自定义标准人数',
  `weight_config_snapshot` text COLLATE utf8mb4_unicode_ci COMMENT '加权配置快照(JSON格式)',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint DEFAULT '0' COMMENT '删除标记 0未删除 1已删除',
  PRIMARY KEY (`id`),
  KEY `idx_check_date` (`check_date`),
  KEY `idx_template_id` (`template_id`),
  KEY `idx_status` (`status`),
  KEY `idx_created_by` (`created_by`),
  KEY `idx_deleted` (`deleted`),
  KEY `idx_plan_id` (`plan_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='日常检查表(V1.0.6)';
/*!40101 SET character_set_client = @saved_cs_client */;

