DROP TABLE IF EXISTS `daily_checks_deprecated`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `daily_checks_deprecated` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `check_date` date NOT NULL COMMENT '检查日期',
  `check_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '检查名称',
  `template_id` bigint DEFAULT NULL COMMENT '使用的模板ID',
  `check_type` tinyint DEFAULT '1' COMMENT '检查类型: 1日常检查 2专项检查',
  `status` tinyint DEFAULT '0' COMMENT '状态: 0未开始 1进行中 2已完成 3已发布',
  `checker_id` bigint DEFAULT NULL COMMENT '检查员ID',
  `checker_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '检查员姓名',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '检查说明',
  `weight_config_id` bigint DEFAULT NULL COMMENT 'Weight config ID',
  `enable_weight` tinyint DEFAULT '0' COMMENT 'Enable weight',
  `custom_standard_size` int DEFAULT NULL COMMENT 'Custom standard size',
  `weight_config_snapshot` json DEFAULT NULL COMMENT '加权配置快照(选中时保存完整配置)',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `deleted` tinyint DEFAULT '0' COMMENT '删除标记: 0正常 1已删除',
  PRIMARY KEY (`id`),
  KEY `idx_check_date` (`check_date`),
  KEY `idx_status` (`status`),
  KEY `idx_template_id` (`template_id`),
  KEY `idx_checker_id` (`checker_id`),
  KEY `idx_weight_config` (`weight_config_id`),
  KEY `idx_date_type` (`check_date`,`check_type`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='日常检查表';
