DROP TABLE IF EXISTS `deduction_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `deduction_items` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `type_id` bigint NOT NULL COMMENT '所属量化类型ID',
  `item_name` varchar(100) NOT NULL COMMENT '扣分项名称',
  `deduct_mode` tinyint NOT NULL COMMENT '扣分模式: 1固定扣分 2按人数扣分 3区间扣分',
  `fixed_score` decimal(5,1) DEFAULT NULL COMMENT '固定扣分分数(模式1使用)',
  `base_score` decimal(5,1) DEFAULT NULL COMMENT '基础扣分分数(模式2使用)',
  `per_person_score` decimal(5,1) DEFAULT NULL COMMENT '每人扣分分数(模式2使用)',
  `range_config` text COMMENT '区间配置JSON(模式3使用)',
  `description` varchar(500) DEFAULT NULL COMMENT '描述',
  `sort_order` int DEFAULT '0' COMMENT '排序',
  `status` tinyint DEFAULT '1' COMMENT '状态: 1启用 0禁用',
  `deleted` tinyint DEFAULT '0' COMMENT '删除标记: 0未删除 1已删除',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `allow_photo` tinyint DEFAULT '1' COMMENT '是否允许上传照片(0否1是)',
  `allow_remark` tinyint DEFAULT '1' COMMENT '是否允许添加备注(0否1是)',
  `allow_students` tinyint DEFAULT '0' COMMENT '是否允许添加学生(0否1是,仅按人次模式有效)',
  `enable_weight` tinyint(1) DEFAULT '0' COMMENT '是否启用加权 0否 1是',
  `weight_config_id` bigint DEFAULT NULL COMMENT '加权配置ID',
  PRIMARY KEY (`id`),
  KEY `idx_type_id` (`type_id`),
  KEY `idx_deleted` (`deleted`)
) ENGINE=InnoDB AUTO_INCREMENT=2000910882871189507 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='扣分项表';
