DROP TABLE IF EXISTS `dormitories`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `dormitories` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `building_id` bigint NOT NULL COMMENT '妤煎畤ID',
  `department_id` bigint DEFAULT NULL COMMENT '所属部门ID',
  `dormitory_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '宿舍编号',
  `floor_number` int NOT NULL COMMENT '楼层',
  `room_usage_type` tinyint NOT NULL DEFAULT '1' COMMENT '房间用途类型: 1学生宿舍 2教职工宿舍 3配电室 4卫生间 5杂物间 6其他',
  `bed_capacity` int NOT NULL DEFAULT '4' COMMENT '床位容量规格: 4/6/8等数字,配电室等为0',
  `room_type` tinyint DEFAULT NULL COMMENT '已废弃-请使用room_usage_type和bed_capacity',
  `bed_count` int DEFAULT '0' COMMENT '实际床位数(通常等于bed_capacity,配电室等为0)',
  `occupied_beds` int DEFAULT '0' COMMENT '已占用床位',
  `gender_type` tinyint DEFAULT '1' COMMENT '性别类型(从宿舍楼自动继承): 1男 2女 3混合',
  `facilities` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '设施说明',
  `notes` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `status` tinyint DEFAULT '1' COMMENT '状态：1正常 2维修 3停用',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人ID',
  `deleted` tinyint DEFAULT '0' COMMENT '是否删除：1是 0否',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_building_dormitory_no` (`building_id`,`dormitory_no`,`deleted`),
  KEY `idx_status` (`status`),
  KEY `idx_deleted` (`deleted`),
  KEY `idx_building_id` (`building_id`),
  KEY `idx_department_id` (`department_id`),
  CONSTRAINT `fk_dormitory_building` FOREIGN KEY (`building_id`) REFERENCES `buildings` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=1994704516099936259 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='宿舍表';
