--
-- Table structure for table `dormitory_building_managers`
--

DROP TABLE IF EXISTS `dormitory_building_managers`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `dormitory_building_managers` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `building_id` bigint NOT NULL COMMENT '宿舍楼ID',
  `user_id` bigint NOT NULL COMMENT '管理员用户ID',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `created_by` bigint DEFAULT NULL COMMENT '创建人ID',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_building_user` (`building_id`,`user_id`),
  KEY `idx_building_id` (`building_id`),
  KEY `idx_user_id` (`user_id`),
