INSERT INTO `notification_records` VALUES (2002407731658498049,2001298830687023106,2002362622019665922,'SINGLE_CHECK','[\"2002277085892063234\"]',NULL,'[1]',NULL,NULL,'2025-12-20 小王学校的日常检查通报_轮次1','<?xml version=\"1.0\" encoding=\"UTF-8\"?>\n<!DOCTYPE html PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional//EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\n<html xmlns=\"http://www.w3.org/1999/xhtml\">\n<head>\n    <meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\" />\n    <style type=\"text/css\">\n        body { font-family: SimSun, serif; font-size: 14px; line-height: 1.6; padding: 40px; }\n        h2 { font-size: 20px; margin-bottom: 10px; }\n        table { margin: 0 auto; }\n        .data-table th, .data-table td { text-align: center; }\n    </style>\n</head>\n<body>\n<div style=\"max-width: 680px; margin: 0 auto; padding: 40px 60px; font-family: SimSun, serif;\">\n<div style=\"text-align: center; margin-bottom: 20px;\">\n<h1 style=\"color: #c00000; font-size: 32px; font-weight: bold; font-family: SimHei, sans-serif; letter-spacing: 8px; margin: 0px;\">经济与信息技术系学生管理办公室</h1>\n</div>\n<hr style=\"border: none; border-top: 2px solid #C00000; margin: 20px 0;\">\n<h2 style=\"text-align: center; font-size: 22px; font-weight: bold; font-family: \'SimHei\', sans-serif; margin: 30px 0; line-height: 1.5;\">关于2025年12月20日学生违纪情况的通报</h2>\n<p style=\"font-size: 16px; line-height: 2; margin-bottom: 15px;\">各院系、各班级：</p>\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">为进一步加强学生日常行为规范管理，维护正常的教学秩序，根据2025年12月20日检查结果，共有 <strong>18</strong> 名学生存在违纪行为，现将有关情况通报如下：</p>\n<div style=\"margin: 25px 0;\"><table class=\"data-table\" style=\"width:100%;border-collapse:collapse;font-size:14px;line-height:1.5;\"><thead><tr><th style=\"border:1px solid #000000;padding:8px;background:#ffffff;color:#000000;font-weight:bold;font-size:14px;text-align:center;vertical-align:middle;\">院系</th><th style=\"border:1px solid #000000;padding:8px;background:#ffffff;color:#000000;font-weight:bold;font-size:14px;text-align:center;vertical-align:middle;\">年级</th><th style=\"border:1px solid #000000;padding:8px;background:#ffffff;color:#000000;font-weight:bold;font-size:14px;text-align:center;vertical-align:middle;\">班级</th><th style=\"border:1px solid #000000;padding:8px;background:#ffffff;color:#000000;font-weight:bold;font-size:14px;text-align:center;vertical-align:middle;\">姓名</th><th style=\"border:1px solid #000000;padding:8px;background:#ffffff;color:#000000;font-weight:bold;font-size:14px;text-align:center;vertical-align:middle;\">班主任</th></tr></thead><tbody><tr style=\"background:#fff;\"><td rowspan=\"8\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">信息工程学院</td><td rowspan=\"8\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">信息工程学院2024级</td><td rowspan=\"3\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">计算机2024级1班</td><td rowspan=\"3\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;\">陈军、周明、马飞</td><td rowspan=\"18\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\"></td></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"><td rowspan=\"5\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">计算机2024级2班</td><td rowspan=\"5\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;\">朱军、林明、罗燕、唐波、韩刚</td></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"><td rowspan=\"10\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">商学院</td><td rowspan=\"5\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">商学院2024级</td><td rowspan=\"5\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">会计2024级4班</td><td rowspan=\"5\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;\">宋敏、唐军、邓明、曹燕、王浩</td></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"><td rowspan=\"5\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">商学院2023级</td><td rowspan=\"5\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;background:#fafafa;font-weight:500;\">会计2023级3班</td><td rowspan=\"5\" style=\"border:1px solid #000000;padding:8px;text-align:center;vertical-align:middle;\">张强、黄杰、周明、吴燕、徐浩</td></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr><tr style=\"background:#fff;\"></tr></tbody></table></div>\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">以上违纪学生的行为已违反了《学生手册》相关规定，根据学校有关规章制度，现予以通报批评，并扣除相应量化考核分数。</p>\n<p style=\"text-indent: 2em; font-size: 16px; line-height: 2; margin-bottom: 15px;\">希望以上同学认真反思，引以为戒，严格遵守学校各项规章制度。各院系、各班级要以此为鉴，进一步加强学生教育管理工作，杜绝类似事件再次发生a 。</p>\n<div style=\"margin-top: 50px; text-align: right; padding-right: 80px;\">\n<p style=\"font-size: 16px; line-height: 2; margin: 0;\">经济与信息技术系学生管理办公室</p>\n<p style=\"font-size: 16px; line-height: 2; margin: 0;\">2025年12月20日&nbsp; &nbsp;&nbsp;</p>\n</div>\n</div>\n</body>\n</html>\n',NULL,18,4,18,'PDF','2025-12-20 小王学校的日常检查通报_轮次1_20251220_235621.pdf','notificatio