--
-- Table structure for table `operation_logs`
--

DROP TABLE IF EXISTS `operation_logs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `operation_logs` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` bigint DEFAULT NULL COMMENT '操作用户ID',
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '用户名',
  `real_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鐪熷疄濮撳悕',
  `operation_module` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鎿嶄綔妯″潡',
  `operation_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鎿嶄綔绫诲瀷',
  `operation_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鎿嶄綔鍚嶇О',
  `request_method` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '璇锋眰鏂规硶',
  `request_url` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '璇锋眰URL',
  `request_params` text COLLATE utf8mb4_unicode_ci COMMENT '璇锋眰鍙傛暟',
  `response_status` int DEFAULT NULL COMMENT '鍝嶅簲鐘舵?鐮',
  `response_time` int DEFAULT NULL COMMENT '鍝嶅簲鏃堕棿(姣??)',
  `operation` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '操作描述(兼容旧字段)',
  `method` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT '' COMMENT '方法名(兼容旧字段)',
  `params` text COLLATE utf8mb4_unicode_ci COMMENT '参数(兼容旧字段)',
  `result` text COLLATE utf8mb4_unicode_ci COMMENT '返回结果(兼容旧字段)',
  `ip_address` varchar(45) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'IP鍦板潃',
  `user_agent` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '用户代理',
  `browser` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '娴忚?鍣',
  `os` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '鎿嶄綔绯荤粺',
  `execute_time` bigint DEFAULT '0' COMMENT '执行时间(兼容旧字段)',
  `status` tinyint DEFAULT '1' COMMENT '状态(兼容旧字段)',
  `error_message` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '错误信息',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  `deleted` tinyint DEFAULT '0' COMMENT '閫昏緫鍒犻櫎(0-鏈?垹闄?1-宸插垹闄?',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_operation` (`operation`),
  KEY `idx_created_at` (`created_at`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=2000908762319167491 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='操作日志表';
/*!40101 SET character_set_client = @saved_cs_client */;

