--
-- Table structure for table `quantification_appeals_deprecated`
--

DROP TABLE IF EXISTS `quantification_appeals_deprecated`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `quantification_appeals_deprecated` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `appeal_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申诉编号',
  `record_id` bigint NOT NULL COMMENT '检查记录ID',
  `class_id` bigint NOT NULL COMMENT '班级ID',
  `class_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '班级名称',
  `item_description` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '扣分项描述',
  `original_score` decimal(10,2) NOT NULL COMMENT '原始扣分',
  `appeal_reason` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申诉理由',
  `evidence_urls` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '证据图片URLs(JSON数组)',
  `appellant_id` bigint NOT NULL COMMENT '申诉人ID',
  `appellant_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '申诉人姓名',
  `status` tinyint DEFAULT '1' COMMENT '状态(1待审核2已通过3已驳回4已撤销)',
  `reviewer_id` bigint DEFAULT NULL COMMENT '审核人ID',
  `reviewer_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '审核人姓名',
  `review_time` datetime DEFAULT NULL COMMENT '审核时间',
  `review_comment` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '审核意见',
  `adjusted_score` decimal(10,2) DEFAULT NULL COMMENT '调整后扣分',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted` tinyint DEFAULT '0',
  PRIMARY KEY (`id`),
  UNIQUE KEY `appeal_code` (`appeal_code`),
  KEY `idx_record` (`record_id`),
  KEY `idx_class` (`class_id`),
  KEY `idx_status` (`status`),
  KEY `idx_appellant` (`appellant_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='量化检查申诉表';
/*!40101 SET character_set_client = @saved_cs_client */;

