DROP TABLE IF EXISTS `stat_analysis_metrics`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `stat_analysis_metrics` (
  `id` bigint NOT NULL,
  `config_id` bigint NOT NULL COMMENT '配置ID',
  `metric_code` varchar(50) NOT NULL COMMENT '指标编码',
  `metric_name` varchar(100) NOT NULL COMMENT '指标名称',
  `metric_type` varchar(30) NOT NULL COMMENT '指标类型',
  `chart_type` varchar(20) DEFAULT 'bar' COMMENT '图表类型',
  `calc_config` json DEFAULT NULL COMMENT '计算配置',
  `display_config` json DEFAULT NULL COMMENT '显示配置',
  `display_order` int DEFAULT '0' COMMENT '显示顺序',
  `is_enabled` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_config_id` (`config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='统计指标配置表';
/*!40101 SET character_set_client = @saved_cs_client */;

