--
-- Table structure for table `stat_analysis_snapshots`
--

DROP TABLE IF EXISTS `stat_analysis_snapshots`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `stat_analysis_snapshots` (
  `id` bigint NOT NULL,
  `config_id` bigint NOT NULL COMMENT '配置ID',
  `snapshot_name` varchar(100) DEFAULT NULL COMMENT '快照名称',
  `snapshot_desc` varchar(500) DEFAULT NULL COMMENT '快照描述',
  `record_ids` json DEFAULT NULL COMMENT '纳入统计的记录ID列表',
  `class_ids` json DEFAULT NULL COMMENT '涉及的班级ID列表',
  `date_range_start` date DEFAULT NULL COMMENT '数据起始日期',
  `date_range_end` date DEFAULT NULL COMMENT '数据截止日期',
  `record_count` int DEFAULT NULL COMMENT '检查记录数',
  `class_count` int DEFAULT NULL COMMENT '涉及班级数',
  `total_score` decimal(10,2) DEFAULT NULL COMMENT '总扣分',
  `avg_score` decimal(10,2) DEFAULT NULL COMMENT '平均扣分',
  `overview_data` json DEFAULT NULL COMMENT '概览数据JSON',
  `metrics_data` json DEFAULT NULL COMMENT '各指标计算结果JSON',
  `result_data` longtext COMMENT '完整结果数据JSON',
  `generated_at` datetime DEFAULT NULL COMMENT '生成时间',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `generated_by` bigint DEFAULT NULL COMMENT '生成者ID',
  `generated_by_name` varchar(50) DEFAULT NULL COMMENT '生成者姓名',
  `is_auto` tinyint(1) DEFAULT '0' COMMENT '是否自动生成',
  `version` int DEFAULT '1' COMMENT '版本号',
  PRIMARY KEY (`id`),
  KEY `idx_config_id` (`config_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='分析结果快照表';
/*!40101 SET character_set_client = @saved_cs_client */;

