/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `stat_category_mappings` (
  `id` bigint NOT NULL,
  `config_id` bigint DEFAULT NULL COMMENT '分析配置ID',
  `plan_id` bigint DEFAULT NULL COMMENT '检查计划ID',
  `template_category_id` bigint DEFAULT NULL COMMENT '模板类别ID',
  `template_category_name` varchar(100) DEFAULT NULL COMMENT '模板类别名称',
  `unified_category_id` bigint DEFAULT NULL COMMENT '统一类别ID',
  `unified_category_name` varchar(100) DEFAULT NULL COMMENT '统一类别名称',
  `unified_code` varchar(50) DEFAULT NULL COMMENT '统一类别编码',
  `unified_name` varchar(100) DEFAULT NULL COMMENT '统一类别名称(旧)',
  `unified_type` varchar(30) DEFAULT NULL COMMENT '统一类别类型',
  `source_category_ids` json DEFAULT NULL COMMENT '源类别ID列表',
  `source_category_names` json DEFAULT NULL COMMENT '源类别名称列表',
  `color` varchar(20) DEFAULT NULL COMMENT '显示颜色',
  `icon` varchar(50) DEFAULT NULL COMMENT '图标',
  `sort_order` int DEFAULT '0' COMMENT '排序序号',
  `is_enabled` tinyint(1) DEFAULT '1' COMMENT '是否启用',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_config_id` (`config_id`),
  KEY `idx_plan_id` (`plan_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='类别映射表';
