--
-- Table structure for table `student_dormitory`
--

DROP TABLE IF EXISTS `student_dormitory`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_dormitory` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `student_id` bigint NOT NULL COMMENT '学生ID',
  `dormitory_id` bigint NOT NULL COMMENT '宿舍ID',
  `bed_number` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '床位号',
  `check_in_date` date DEFAULT NULL COMMENT '入住日期',
  `check_out_date` date DEFAULT NULL COMMENT '退宿日期(NULL表示当前在住)',
  `status` tinyint DEFAULT '1' COMMENT '状态: 1在住 2已退宿 3调换中',
  `change_reason` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '变动原因',
  `remark` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `created_by` bigint DEFAULT NULL COMMENT '创建人',
  `updated_by` bigint DEFAULT NULL COMMENT '更新人',
  `deleted` tinyint DEFAULT '0' COMMENT '删除标记: 0正常 1删除',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_student_status` (`student_id`,`status`) COMMENT '同一学生同一时间只能有一个在住记录',
  KEY `idx_student_id` (`student_id`),
  KEY `idx_dormitory_id` (`dormitory_id`),
  KEY `idx_status` (`status`),
  KEY `idx_check_in_date` (`check_in_date`)
) ENGINE=InnoDB AUTO_INCREMENT=1828 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='学生住宿记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

