--
-- Table structure for table `student_evaluation_results`
--

DROP TABLE IF EXISTS `student_evaluation_results`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_evaluation_results` (
  `id` bigint NOT NULL COMMENT '主键ID',
  `evaluation_period_id` bigint NOT NULL COMMENT '综测周期ID',
  `semester_id` bigint NOT NULL COMMENT '学期ID',
  `student_id` bigint NOT NULL COMMENT '学生ID',
  `student_no` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '学号',
  `student_name` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '姓名',
  `class_id` bigint DEFAULT NULL COMMENT '班级ID',
  `class_name` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '班级名称',
  `grade_id` bigint DEFAULT NULL COMMENT '年级ID',
  `department_id` bigint DEFAULT NULL COMMENT '系部ID',
  `moral_base_score` decimal(10,2) DEFAULT '0.00' COMMENT '德育基础分',
  `moral_bonus_score` decimal(10,2) DEFAULT '0.00' COMMENT '德育奖励分',
  `moral_deduct_score` decimal(10,2) DEFAULT '0.00' COMMENT '德育扣分',
  `moral_total_score` decimal(10,2) DEFAULT '0.00' COMMENT '德育总分',
  `moral_weighted_score` decimal(10,2) DEFAULT '0.00' COMMENT '德育加权分',
  `intellectual_base_score` decimal(10,2) DEFAULT '0.00' COMMENT '智育基础分',
  `intellectual_bonus_score` decimal(10,2) DEFAULT '0.00' COMMENT '智育奖励分',
  `intellectual_deduct_score` decimal(10,2) DEFAULT '0.00' COMMENT '智育扣分',
  `intellectual_total_score` decimal(10,2) DEFAULT '0.00' COMMENT '智育总分',
  `intellectual_weighted_score` decimal(10,2) DEFAULT '0.00' COMMENT '智育加权分',
  `physical_base_score` decimal(10,2) DEFAULT '0.00' COMMENT '体育基础分',
  `physical_bonus_score` decimal(10,2) DEFAULT '0.00' COMMENT '体育奖励分',
  `physical_deduct_score` decimal(10,2) DEFAULT '0.00' COMMENT '体育扣分',
  `physical_total_score` decimal(10,2) DEFAULT '0.00' COMMENT '体育总分',
  `physical_weighted_score` decimal(10,2) DEFAULT '0.00' COMMENT '体育加权分',
  `aesthetic_base_score` decimal(10,2) DEFAULT '0.00' COMMENT '美育基础分',
  `aesthetic_bonus_score` decimal(10,2) DEFAULT '0.00' COMMENT '美育奖励分',
  `aesthetic_deduct_score` decimal(10,2) DEFAULT '0.00' COMMENT '美育扣分',
  `aesthetic_total_score` decimal(10,2) DEFAULT '0.00' COMMENT '美育总分',
  `aesthetic_weighted_score` decimal(10,2) DEFAULT '0.00' COMMENT '美育加权分',
  `labor_base_score` decimal(10,2) DEFAULT '0.00' COMMENT '劳育基础分',
  `labor_bonus_score` decimal(10,2) DEFAULT '0.00' COMMENT '劳育奖励分',
  `labor_deduct_score` decimal(10,2) DEFAULT '0.00' COMMENT '劳育扣分',
  `labor_total_score` decimal(10,2) DEFAULT '0.00' COMMENT '劳育总分',
  `labor_weighted_score` decimal(10,2) DEFAULT '0.00' COMMENT '劳育加权分',
  `development_base_score` decimal(10,2) DEFAULT '0.00' COMMENT '发展素质基础分',
  `development_bonus_score` decimal(10,2) DEFAULT '0.00' COMMENT '发展素质奖励分',
  `development_deduct_score` decimal(10,2) DEFAULT '0.00' COMMENT '发展素质扣分',
  `development_total_score` decimal(10,2) DEFAULT '0.00' COMMENT '发展素质总分',
  `development_weighted_score` decimal(10,2) DEFAULT '0.00' COMMENT '发展素质加权分',
  `total_score` decimal(10,2) DEFAULT '0.00' COMMENT '综测总分',
  `class_rank` int DEFAULT NULL COMMENT '班级排名',
  `class_total` int DEFAULT NULL COMMENT '班级参评人数',
  `grade_rank` int DEFAULT NULL COMMENT '年级排名',
  `grade_total` int DEFAULT NULL COMMENT '年级参评人数',
  `department_rank` int DEFAULT NULL COMMENT '系部排名',
  `department_total` int DEFAULT NULL COMMENT '系部参评人数',
  `has_punishment` tinyint DEFAULT '0' COMMENT '是否有处分',
  `punishment_type` int DEFAULT NULL COMMENT '处分类型',
  `punishment_effect` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '处分影响说明',
  `status` tinyint DEFAULT '0' COMMENT '状态: 0待计算,1已计算,2待审核,3已审核,4公示中,5已生效,6已归档',
  `version` int DEFAULT '1' COMMENT '版本号',
  `calculated_at` datetime DEFAULT NULL COMMENT '计算时间',
  `reviewed_by` bigint DEFAULT NULL COMMENT '审核人',
  `reviewed_at` datetime DEFAULT NULL COMMENT '审核时间',
  `remarks` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_period_student` (`evaluation_period_id`,`student_id`),
  KEY `idx_evaluation_period_id` (`evaluation_period_id`),
  KEY `idx_semester_id` (`semester_id`),
  KEY `idx_student_id` (`student_id`),
  KEY `idx_class_id` (`class_id`),
  KEY `idx_department_id` (`department_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='学生综测结果主表';
/*!40101 SET character_set_client = @saved_cs_client */;

