--
-- Table structure for table `student_honor_application`
--

DROP TABLE IF EXISTS `student_honor_application`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `student_honor_application` (
  `id` bigint NOT NULL COMMENT '主键ID',
  `application_code` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '申报编号',
  `semester_id` bigint NOT NULL COMMENT '学期ID',
  `evaluation_period_id` bigint DEFAULT NULL COMMENT '综测周期ID',
  `student_id` bigint NOT NULL COMMENT '学生ID',
  `honor_type_id` bigint DEFAULT NULL COMMENT '荣誉类型ID',
  `honor_level_config_id` bigint DEFAULT NULL COMMENT '荣誉等级配置ID',
  `honor_name` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '荣誉名称/竞赛名称',
  `honor_level` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '级别',
  `honor_rank` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '名次/等级',
  `honor_date` date DEFAULT NULL COMMENT '获得日期',
  `issuing_authority` varchar(200) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '颁发机构',
  `certificate_no` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '证书编号',
  `description` text COLLATE utf8mb4_unicode_ci COMMENT '详细描述',
  `attachments` text COLLATE utf8mb4_unicode_ci COMMENT '附件列表(JSON)',
  `related_application_id` bigint DEFAULT NULL COMMENT '关联申报ID(同一事迹更高级别)',
  `is_highest_level` tinyint DEFAULT '1' COMMENT '是否该事迹最高级别',
  `same_event_group` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '同一事迹分组标识',
