DROP TABLE IF EXISTS `system_configs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `system_configs` (
  `id` bigint NOT NULL COMMENT '涓婚敭ID',
  `config_key` varchar(100) NOT NULL COMMENT '閰嶇疆閿?鍞?竴)',
  `config_value` text NOT NULL COMMENT '閰嶇疆鍊',
  `config_type` varchar(20) NOT NULL DEFAULT 'string' COMMENT '鍊肩被鍨?string/number/boolean/json)',
  `config_group` varchar(50) NOT NULL COMMENT '閰嶇疆鍒嗙粍(system/business/ui绛?',
  `config_label` varchar(100) NOT NULL COMMENT '閰嶇疆鏍囩?(涓?枃鍚嶇О)',
  `config_desc` varchar(500) DEFAULT NULL COMMENT '閰嶇疆鎻忚堪',
  `is_system` tinyint NOT NULL DEFAULT '0' COMMENT '鏄?惁绯荤粺鍐呯疆(0-鍚?1-鏄?绯荤粺鍐呯疆涓嶅彲鍒犻櫎)',
  `sort_order` int DEFAULT '0' COMMENT '鎺掑簭鍙',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '鐘舵?(1-鍚?敤,0-绂佺敤)',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '鏇存柊鏃堕棿',
  `deleted` int NOT NULL DEFAULT '0' COMMENT '閫昏緫鍒犻櫎鏍囧織(0-鏈?垹闄?1-宸插垹闄?',
  PRIMARY KEY (`id`),
  UNIQUE KEY `config_key` (`config_key`),
  KEY `idx_config_key` (`config_key`),
  KEY `idx_config_group` (`config_group`),
  KEY `idx_status` (`status`),
  KEY `idx_deleted` (`deleted`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='绯荤粺閰嶇疆琛';
/*!40101 SET character_set_client = @saved_cs_client */;

