  CONSTRAINT `fk_tc_template` FOREIGN KEY (`template_id`) REFERENCES `check_templates` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2000911241358352389 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='模板-类别关联表';
